sql:
SELECT client_id, first_name, last_name, annual_income
FROM clients
WHERE annual_income > (SELECT AVG(annual_income) FROM clients);

SELECT AVG(premium_amount) AS overall_avg_premium
FROM policies
WHERE policy_type = 'term';

SELECT COUNT(DISTINCT client_id) 
FROM policies 
WHERE issue_date >= DATE('now', '-1 month');

SELECT AVG(total_savings) AS average_savings
FROM (
    SELECT client_id, SUM(balance) AS total_savings
    FROM savings_accounts
    GROUP BY client_id
) AS subquery;

SELECT client_id, AVG(interest_rate) AS AverageSavingsInterestRate
FROM savings_accounts
GROUP BY client_id;

external_knowledge:
- Treasure chests represent the total cash values of policies;
- Sowing seeds is a metaphor for having policies; 
- A client with more than one seed means they have more than one policy.

- "nurturing their financial trees" refers to maintaining active insurance policies;
- "policies that bear fruit more than 5000 annually" refers to policies with a premium amount greater than 5000;
- "fleeting ones" refers to policies of type 'Term';
- "used their savings to water these trees" refers to making a transaction for the premium from their savings.
